13	      for (let dy = -1; dy <= 1; dy++) {
14	        if (dx === 0 && dy === 0) continue;
15	        const nx = x + dx;
16	        const ny = y + dy;
17	        const key = `${nx},${ny}`;
18	        neighborCounts.set(key, (neighborCounts.get(key) ?? 0) + 1);
19	      }
20	    }
21	  }
22	
23	  const result: Cell[] = [];
24	
25	  for (const [key, count] of neighborCounts) {
26	    const isAlive = liveCells.has(key);
27	    if (isAlive && (count === 2 || count === 3)) {
28	      const [xStr, yStr] = key.split(',');
